solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string feature;
        std::cin >> feature;
        if (feature == "auto" || feature == "nullptr" ||
            feature == "lambda" || feature == "unique_ptr") {
            std::cout << "C++11\n";
        } else {
            std::cout << "pre-C++11\n";
        }
    }
    return 0;
}

